import React, { useEffect, useRef, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { getChannel } from '../services/api';
import Hls from 'hls.js';

const RADIO_CATEGORIES = ['radio', 'music', 'música'];
const isRadio = (cat) => RADIO_CATEGORIES.some(r => cat?.toLowerCase().includes(r));

const getYoutubeEmbedUrl = (url) => {
  if (!url) return null;
  const match = url.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/)([^&\s]+)/);
  if (match) return `https://www.youtube.com/embed/${match[1]}?autoplay=1&rel=0&modestbranding=1&iv_load_policy=3&fs=1&color=white&controls=1`;
  const channelMatch = url.match(/youtube\.com\/channel\/([^/]+)/);
  if (channelMatch) return `https://www.youtube.com/embed/live_stream?channel=${channelMatch[1]}&autoplay=1&rel=0&modestbranding=1`;
  return null;
};

const isYoutube = (url) => url?.includes('youtube.com') || url?.includes('youtu.be');

const ChannelPlayer = () => {
  const { id } = useParams();
  const videoRef = useRef(null);
  const audioRef = useRef(null);
  const hlsRef = useRef(null);
  const [channel, setChannel] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [streamError, setStreamError] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [volume, setVolume] = useState(1);
  const [isMuted, setIsMuted] = useState(false);

  useEffect(() => {
    loadChannel();
    return () => {
      if (hlsRef.current) { hlsRef.current.destroy(); hlsRef.current = null; }
    };
  }, [id]);

  const loadChannel = async () => {
    try {
      const data = await getChannel(id);
      setChannel(data);
      setTimeout(() => loadStream(data), 500);
    } catch (err) {
      setError('Canal no encontrado');
    } finally {
      setLoading(false);
    }
  };

  const loadStream = (data) => {
    const url = data.stream_url;
    const radio = isRadio(data.category);
    if (isYoutube(url)) return;
    if (radio) loadAudio(url);
    else loadVideo(url);
  };

  const loadAudio = (url) => {
    const audio = audioRef.current;
    if (!audio) return;
    audio.src = url;
    audio.volume = volume;
    audio.play().then(() => setIsPlaying(true)).catch(() => setStreamError(true));
  };

  const loadVideo = (url) => {
    const video = videoRef.current;
    if (!video) return;

    if (hlsRef.current) { hlsRef.current.destroy(); hlsRef.current = null; }

    const isM3U8 = url.includes('.m3u8') || url.includes('.ts');
    // Usar proxy para evitar CORS
    const finalUrl = isM3U8 ? `http://localhost:5000/api/channels/fetch-m3u?url=${encodeURIComponent(url)}` : url;

    if (isM3U8 && Hls.isSupported()) {
      const hls = new Hls({ 
        enableWorker: true, 
        lowLatencyMode: true,
        xhrSetup: (xhr) => { xhr.withCredentials = false; }
      });
      hls.loadSource(finalUrl);
      hls.attachMedia(video);
      hls.on(Hls.Events.MANIFEST_PARSED, () => {
        video.play().then(() => setIsPlaying(true)).catch(() => {});
      });
      hls.on(Hls.Events.ERROR, (e, data) => {
        if (data.fatal) {
          // Si falla el proxy, intentar directo
          hls.loadSource(url);
        }
      });
      hlsRef.current = hls;
    } else {
      video.src = url;
      video.play().then(() => setIsPlaying(true)).catch(() => setStreamError(true));
    }
  };

  const togglePlay = () => {
    const media = isRadio(channel?.category) ? audioRef.current : videoRef.current;
    if (!media) return;
    if (isPlaying) { media.pause(); setIsPlaying(false); }
    else { media.play(); setIsPlaying(true); }
  };

  const handleVolume = (e) => {
    const val = parseFloat(e.target.value);
    setVolume(val);
    setIsMuted(val === 0);
    const media = isRadio(channel?.category) ? audioRef.current : videoRef.current;
    if (media) media.volume = val;
  };

  const toggleMute = () => {
    const media = isRadio(channel?.category) ? audioRef.current : videoRef.current;
    if (!media) return;
    media.muted = !isMuted;
    setIsMuted(!isMuted);
  };

  if (loading) return (
    <div className="flex justify-center items-center h-[70vh]">
      <div className="animate-spin rounded-full h-16 w-16 border-t-2 border-b-2 border-red-600"></div>
    </div>
  );

  if (error) return (
    <div className="p-4 text-white text-center">
      <p className="text-red-400 mb-4">{error}</p>
      <Link to="/" className="bg-red-600 px-4 py-2 rounded">Volver</Link>
    </div>
  );

  const radio = isRadio(channel?.category);

  return (
    <div className="bg-gray-900 min-h-screen">
      {/* Header */}
      <div className="p-4 bg-gray-800 flex items-center justify-between">
        <Link to={radio ? '/radio' : '/channels'} className="text-gray-400 hover:text-white text-sm">
          ← {radio ? 'Radio' : 'TV en Vivo'}
        </Link>
        <span className="bg-red-600 text-white px-3 py-1 rounded-full text-xs font-bold animate-pulse">
          🔴 EN VIVO
        </span>
      </div>

      {radio ? (
        /* ===== REPRODUCTOR RADIO ===== */
        <div className="flex flex-col items-center justify-center px-6 py-16">
          {/* Logo animado */}
          <div className={`relative mb-8 ${isPlaying ? 'animate-pulse' : ''}`}>
            <div className={`absolute inset-0 rounded-full bg-red-600 opacity-20 ${isPlaying ? 'animate-ping' : ''}`}></div>
            {channel.logo ? (
              <img
                src={channel.logo}
                alt={channel.name}
                className="w-48 h-48 object-contain bg-white rounded-full p-4 shadow-2xl relative z-10"
                onError={(e) => e.target.style.display = 'none'}
              />
            ) : (
              <div className="w-48 h-48 bg-gray-700 rounded-full flex items-center justify-center text-7xl shadow-2xl relative z-10">
                📻
              </div>
            )}
          </div>

          {/* Info */}
          <h1 className="text-3xl font-bold text-white mb-1">{channel.name}</h1>
          <p className="text-gray-400 mb-2">{channel.country}</p>
          <span className="bg-gray-700 text-gray-300 px-3 py-1 rounded-full text-sm mb-10">{channel.category}</span>

          {/* Ondas animadas */}
          {isPlaying && (
            <div className="flex items-end gap-1 mb-8 h-12">
              {[...Array(20)].map((_, i) => (
                <div
                  key={i}
                  className="w-1.5 bg-red-500 rounded-full"
                  style={{
                    height: `${Math.random() * 100}%`,
                    animation: `wave ${0.5 + Math.random() * 0.5}s ease-in-out infinite alternate`,
                    animationDelay: `${i * 0.05}s`
                  }}
                />
              ))}
            </div>
          )}

          {/* Controles */}
          <div className="flex items-center gap-6 mb-8">
            <button onClick={toggleMute} className="text-gray-400 hover:text-white text-2xl">
              {isMuted ? '🔇' : '🔊'}
            </button>
            <button
              onClick={togglePlay}
              className="w-20 h-20 bg-red-600 hover:bg-red-700 rounded-full flex items-center justify-center text-4xl shadow-lg transition-all hover:scale-110"
            >
              {isPlaying ? '⏸' : '▶️'}
            </button>
            <div className="w-8"></div>
          </div>

          {/* Volumen */}
          <div className="flex items-center gap-3 w-64">
            <span className="text-gray-400 text-sm">🔈</span>
            <input
              type="range"
              min="0"
              max="1"
              step="0.05"
              value={isMuted ? 0 : volume}
              onChange={handleVolume}
              className="flex-1 accent-red-600"
            />
            <span className="text-gray-400 text-sm">🔊</span>
          </div>

          {/* Audio oculto */}
          <audio ref={audioRef} onEnded={() => setIsPlaying(false)} style={{ display: 'none' }} />

          {streamError && (
            <div className="mt-6 text-center">
              <p className="text-gray-400 mb-3">No se puede reproducir esta emisora</p>
              <button onClick={() => { setStreamError(false); loadAudio(channel.stream_url); }} className="bg-green-600 hover:bg-green-700 px-4 py-2 rounded text-sm mr-2">
                🔄 Reintentar
              </button>
            </div>
          )}
        </div>

      ) : (
        /* ===== REPRODUCTOR TV ===== */
        <div>
          <div className="p-4 bg-gray-800 flex items-center gap-4">
            {channel.logo && (
              <img src={channel.logo} alt={channel.name} className="w-12 h-12 object-contain bg-white rounded p-1" onError={(e) => e.target.style.display = 'none'} />
            )}
            <div>
              <h1 className="text-white text-xl font-bold">{channel.name}</h1>
              <p className="text-gray-400 text-sm">{channel.country} • {channel.category}</p>
            </div>
          </div>

          <div className="w-full bg-black">
            {isYoutube(channel.stream_url) ? (
              <div 
                id="yt-container"
                className="relative w-full overflow-hidden" 
                style={{ paddingBottom: '56.25%', height: 0 }}
              >
                <iframe
                  src={getYoutubeEmbedUrl(channel.stream_url)}
                  style={{
                    position: 'absolute',
                    top: '-60px',
                    left: '-2px',
                    width: 'calc(100% + 4px)',
                    height: 'calc(100% + 120px)',
                    border: 'none',
                  }}
                  frameBorder="0"
                  allow="autoplay; fullscreen; picture-in-picture; encrypted-media"
                  allowFullScreen
                  title={channel.name}
                />
                {/* Máscara superior - bloquea clic al canal */}
                <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: '70px', background: '#000', zIndex: 10, pointerEvents: 'auto' }} />
                {/* Gradiente hover - bloquea clic al título */}
                <div style={{ position: 'absolute', top: '70px', left: 0, right: 0, height: '60px', background: 'linear-gradient(to bottom, #000, transparent)', zIndex: 10, pointerEvents: 'auto' }} />
                {/* Bloquear esquina superior izquierda (logo YouTube) */}
                <div style={{ position: 'absolute', top: '70px', left: 0, width: '120px', height: '40px', background: 'transparent', zIndex: 10, pointerEvents: 'auto' }} />
                {/* Bloquear esquina superior derecha (botones) */}
                <div style={{ position: 'absolute', top: '70px', right: 0, width: '120px', height: '40px', background: 'transparent', zIndex: 10, pointerEvents: 'auto' }} />
                {/* Máscara inferior */}
                <div style={{ position: 'absolute', bottom: 0, left: 0, right: 0, height: '10px', background: '#000', zIndex: 10, pointerEvents: 'none' }} />
                {/* Botón fullscreen propio */}
                <button
                  onClick={() => {
                    const el = document.getElementById('yt-container');
                    if (el.requestFullscreen) el.requestFullscreen();
                    else if (el.webkitRequestFullscreen) el.webkitRequestFullscreen();
                  }}
                  style={{ position: 'absolute', bottom: '12px', right: '12px', zIndex: 20 }}
                  className="bg-black bg-opacity-70 hover:bg-opacity-100 text-white px-3 py-1 rounded text-sm"
                >
                  ⛶ Pantalla completa
                </button>
              </div>
            ) : streamError ? (
              <div className="w-full h-64 flex flex-col items-center justify-center bg-gray-900 gap-4">
                <p className="text-gray-400">Este canal no se puede reproducir en el navegador</p>
                <div className="flex gap-3">
                  <button onClick={() => { setStreamError(false); loadVideo(channel.stream_url); }} className="bg-green-600 hover:bg-green-700 px-4 py-2 rounded text-white text-sm">
                    🔄 Reintentar
                  </button>
                  <a href={`vlc://${channel.stream_url}`} className="bg-orange-600 hover:bg-orange-700 px-4 py-2 rounded text-white text-sm">
                    📺 Abrir en VLC
                  </a>
                </div>
              </div>
            ) : (
              <video ref={videoRef} className="w-full h-auto max-h-[70vh]" controls playsInline style={{ background: '#000' }} />
            )}
          </div>
        </div>
      )}

      <style>{`
        @keyframes wave {
          from { transform: scaleY(0.3); }
          to { transform: scaleY(1); }
        }
      `}</style>
    </div>
  );
};

export default ChannelPlayer;
